//auth context
//use auth hook used in different parts

import React, { createContext, useContext, useEffect, useState } from "react";
import { auth } from "../components/firebase_setup";
import { onAuthStateChanged } from "firebase/auth";


const AuthContext = createContext();

export function useAuth() {
    return useContext(AuthContext);
}

export function AuthProvider ( {children} ) {
    const [currentUser, SetcurrentUser] = useState(null);  //setting the state of the user (valid or not)
    const [LoggedIn, SetLoggedIn] = useState(false);       //if the user is logged in
    const [loading, setloading] = useState(true);           //trying to load the current users stat

    useEffect(()=>{                                        //listening to event changes, uses the auth
        const listen = onAuthStateChanged(auth, initializeUser);     // initializeUser is like a function that is when the user is successfully logged in
        return listen;
    }, [])

    async function initializeUser(user) {
        //if the user is a valid user and has value then set logged in to true and set the users state to the user
        if (user){
            SetcurrentUser({ ...user });
            SetLoggedIn(true);
        } else {
            SetcurrentUser(null);
            SetLoggedIn(false);
        }
        setloading(false)
    }

    const value = {
        currentUser,
        LoggedIn,
        loading
    }

    return (
        <AuthContext.Provider value = {value}>
            {!loading && children}
        </AuthContext.Provider>
    )
}
